import React from "react";
import { Card, CardImg, CardTitle, CardDeck, CardBody } from "reactstrap";
import { baseurl } from "../../baseurl";

const Gallery = (props) => {
  return (
    <div>
      <CardDeck style={{ marginLeft: "1px" }}>
        <Card className="card">
          <CardImg
            top
            src={baseurl + props.info.img}
            alt="Card image cap"
            className="b_img"
          />
          <CardBody>
            <CardTitle
              style={{ cursor: "pointer" }}
              onClick={props.PhotoSelect}
            >
              {" "}
              {props.info.name}{" "}
            </CardTitle>
          </CardBody>
        </Card>
      </CardDeck>
    </div>
  );
};
export default Gallery;
