import React from "react";
import { Card, CardImg,CardImgOverlay,CardTitle, CardBody, CardDeck } from "reactstrap";
import { baseurl } from "../../baseurl";
import CommentForm from "./CommentForm";
import LoadComments from "./LoadComments";

const PhotoDetail = (props) => {    
  return (
    <div style={{marginLeft:"5%"}} >
      <CardDeck  >
        <Card className="cardd">
          <CardImg
            top
            src={baseurl + props.info.img}
            alt="Card image cap"
            className="cdd_img"
          />
          <CardImgOverlay>
            <span className="clbtn" onClick={props.infoClose} >&times;</span>
          </CardImgOverlay>
          <CardBody style={{overflowY:"auto",maxHeight:"300px"}}>
            <CardTitle > {props.info.name} </CardTitle>
            <hr />
              <LoadComments
              comments={props.comments}
              commentIsLoading={props.commentIsLoading}
            /> 
          </CardBody>
        </Card>
      </CardDeck>
      <hr />
       <CommentForm PhotoId={props.info.id} cnpaddComment={props.cnpaddComment} />
        
    </div>
  );
};
export default PhotoDetail;
