import React, { Component } from "react";
import Gallery from "./Gallery";
import PhotoDetail from "./PhotoDetail";
import { Container, Row, Col } from "reactstrap";
import { connect } from "react-redux";
import {baseurl} from "../../baseurl";
import axios from 'axios';
import DefaultPhoto from "./DefaultPhoto";

import {
  archaddComment,
  archfetchComments,
  archfetchPhotose,
} from "../../../redux/actionCreator";

const mapStateToProps = (state) => {
  return {
    photo: state.arch_photose,
    comment: state.archcomments,
  };
};
const mapDispatchToProps = (dispatch) => {
  return {
    archaddComment: (PhotoId, author, comment) =>
      dispatch(archaddComment(PhotoId, author, comment)),
    archfetchPhotose: () => dispatch(archfetchPhotose()),
    archfetchComments: () => dispatch(archfetchComments()),
  };
};
class MainArchitecture extends Component {
  state = {
    selectedphoto: null,
    default:[]
  };
  onPhotoSelect = (photo) => {
    this.setState({ selectedphoto: photo });
  };
  onClose=()=>{
    this.setState({selectedphoto:null});
  }
  componentDidMount() {
    this.props.archfetchPhotose();
    this.props.archfetchComments();
    axios.get(baseurl+"Default")
        .then(res=>res.data[4])
        .then(data=>{this.setState({default:data});}); 
  }
  render() {
    const gallery = this.props.photo.arch_photose.map((item) => {
      return (
        <Gallery
          info={item}
          key={item.id}
          PhotoSelect={() => this.onPhotoSelect(item)}
        />
      );
    });
    let photodetail = null;
    if (this.state.selectedphoto != null) {
      const comments = this.props.comment.archcomments.filter(
        (comment) => comment.ArchphotoId === this.state.selectedphoto.id
      );

      photodetail = (
        <PhotoDetail
          info={this.state.selectedphoto}
          comments={comments}
          archaddComment={this.props.archaddComment}
          commentIsLoading={this.props.comment.isLoading}
          infoClose={()=>this.onClose()}
        />
      );
    }
    else{
      photodetail =(<DefaultPhoto info={this.state.default}/>)

    }
    return (
      <div>        
        <Container
          className="themed-container"
          fluid={true}
          style={{ float: "left" }}
        >
          <Row>
            <Col md="7">
              <Row>{gallery}</Row>
            </Col>
            <Col md="4">{photodetail}</Col>
          </Row>
        </Container>
      </div>
    );
  }
}

export default connect(mapStateToProps, mapDispatchToProps)(MainArchitecture);
