import React from "react";
import { Card, CardImg,CardBody, CardDeck } from "reactstrap";
import { baseurl } from "../../baseurl";

const DefaultPhoto = (props) => {  
  return (
    <div style={{marginLeft:"5%"}}>
      <CardDeck>
        <Card style={{border:"none"}}>
          <CardImg
            top
            src={baseurl+props.info.gallery}
            alt="Card image cap"
            className="def_img"
          />          
          <CardBody>
              <h2>{props.info.name}</h2>                    
          </CardBody>
        </Card>
      </CardDeck>      
    </div>
  );
}
export default DefaultPhoto;
