import React, { Component } from "react";
import Gallery from "./Gallery";
import PhotoDetail from "./PhotoDetail";
import { Container, Row, Col } from "reactstrap";
import { connect } from "react-redux";
import {baseurl} from "../../baseurl";
import axios from 'axios';
import DefaultPhoto from "./DefaultPhoto";
import {
  cnpaddComment,
  cnpfetchComments,
  cnpfetchPhotose,
} from "../../../redux/actionCreator";

const mapStateToProps = (state) => {
  return {
    photo: state.cnp_photose,
    comment: state.cnpcomments,
  };
};
const mapDispatchToProps = (dispatch) => {
  return {
    cnpaddComment: (PhotoId, author, comment) =>
      dispatch(cnpaddComment(PhotoId, author, comment)),
    cnpfetchPhotose: () => dispatch(cnpfetchPhotose()),
    cnpfetchComments: () => dispatch(cnpfetchComments()),
  };
};
class MainConceptual extends Component {
  state = {
    selectedphoto: null,
    default:[]
  };
  onPhotoSelect = (photo) => {
    this.setState({ selectedphoto: photo });
  };
  onClose=()=>{
    this.setState({selectedphoto:null});
  }
  componentDidMount() {
    this.props.cnpfetchPhotose();
    this.props.cnpfetchComments();
    axios.get(baseurl+"Default")
        .then(res=>res.data[5])
        .then(data=>{this.setState({default:data});});  

  }
  render() {
    const gallery = this.props.photo.cnp_photose.map((item) => {
      return (
        <Gallery
          info={item}
          key={item.id}
          PhotoSelect={() => this.onPhotoSelect(item)}
        />
      );
    });
    let photodetail = null;
    if (this.state.selectedphoto != null) {
      const comments = this.props.comment.cnpcomments.filter(
        (comment) => comment.CnpphotoId === this.state.selectedphoto.id
      );

      photodetail = (
        <PhotoDetail
          info={this.state.selectedphoto}
          comments={comments}
          cnpaddComment={this.props.cnpaddComment}
          commentIsLoading={this.props.comment.isLoading}
          infoClose={()=>this.onClose()}
        />
      );
    }
    else{
      photodetail =(<DefaultPhoto info={this.state.default}/>)
    }
    return (
      <div id="/gallery">        
        <Container
          className="themed-container"
          fluid={true}
          style={{ float: "left" }}
        >
          <Row>
            <Col md="7">
              <Row>{gallery}</Row>
            </Col>
            <Col md="4">{photodetail}</Col>
          </Row>
        </Container>
      </div>
    );
  }
}

export default connect(mapStateToProps, mapDispatchToProps)(MainConceptual);
