import React, { Component } from "react";
import Gallery from "./Gallery";
import PhotoDetail from "./PhotoDetail";
import { Container, Row, Col } from "reactstrap";
import { connect } from "react-redux";
import {baseurl} from "../../baseurl";
import axios from 'axios';
import DefaultPhoto from "./DefaultPhoto";

import {
  lndaddComment,
  lndfetchComments,
  lndfetchPhotose,
} from "../../../redux/actionCreator";

const mapStateToProps = (state) => {
  return {
    photo: state.lnd_photose,
    comment: state.lndcomments,
  };
};
const mapDispatchToProps = (dispatch) => {
  return {
    lndaddComment: (PhotoId, author, comment) =>
      dispatch(lndaddComment(PhotoId, author, comment)),
    lndfetchPhotose: () => dispatch(lndfetchPhotose()),
    lndfetchComments: () => dispatch(lndfetchComments()),
  };
};
class MainLandscape extends Component {
  state = {
    selectedphoto: null,
    default:[]
  };
  onPhotoSelect = (photo) => {
    this.setState({ selectedphoto: photo });
  };
  onClose=()=>{
    this.setState({selectedphoto:null});
  }
  componentDidMount() {
    this.props.lndfetchPhotose();
    this.props.lndfetchComments();
    axios.get(baseurl+"Default")
        .then(res=>res.data[3])
        .then(data=>{this.setState({default:data});});
  }
  render() {
    const gallery = this.props.photo.lnd_photose.map((item) => {
      return (
        <Gallery
          info={item}
          key={item.id}
          PhotoSelect={() => this.onPhotoSelect(item)}
        />
      );
    });
    let photodetail = null;
    if (this.state.selectedphoto != null) {
      const comments = this.props.comment.lndcomments.filter(
        (comment) => comment.LndphotoId === this.state.selectedphoto.id
      );

      photodetail = (
        <PhotoDetail
          info={this.state.selectedphoto}
          comments={comments}
          lndaddComment={this.props.lndaddComment}
          commentIsLoading={this.props.comment.isLoading}
          infoClose={()=>this.onClose()}
        />
      );
    }
    else{
      photodetail =(<DefaultPhoto info={this.state.default}/>)
    }
    return (
      <div id="/gallery">        
        <Container
          className="themed-container"
          fluid={true}
          style={{ float: "left" }}
        >
          <Row>
            <Col md="7">
              <Row>{gallery}</Row>
            </Col>
            <Col md="4">{photodetail}</Col>
          </Row>
        </Container>
      </div>
    );
  }
}

export default connect(mapStateToProps, mapDispatchToProps)(MainLandscape);
