import React, { Component } from "react";
import Gallery from "./Gallery";
import PhotoDetail from "./PhotoDetail";
import { Container, Row, Col } from "reactstrap";
import { connect } from "react-redux";
import DefaultPhoto from "./DefaultPhoto";
import axios from 'axios';
import {baseurl} from "../../baseurl";
import {
  absaddComment,
  absfetchComments,
  absfetchPhotose,
} from "../../../redux/actionCreator";

const mapStateToProps = (state) => {
  return {
    photo: state.abs_photose,
    comment: state.abscomments,
  };
};
const mapDispatchToProps = (dispatch) => {
  return {
    absaddComment: (PhotoId, author, comment) =>
      dispatch(absaddComment(PhotoId, author, comment)),
    absfetchPhotose: () => dispatch(absfetchPhotose()),
    absfetchComments: () => dispatch(absfetchComments()),
  };
};
class Mainabstract extends Component {
  state = {
    selectedphoto: null,
    default:[],
  };
  onPhotoSelect = (photo) => {
    this.setState({ selectedphoto: photo });
  };
  onClose=()=>{
    this.setState({selectedphoto:null});
  }
  componentDidMount() {
    this.props.absfetchPhotose();
    this.props.absfetchComments();
    axios.get(baseurl+"Default")
        .then(res=>res.data[0])
        .then(data=>{this.setState({default:data});}); 
  }
  render() {
    const gallery = this.props.photo.abs_photose.map((item) => {
      return (
        <Gallery
          info={item}
          key={item.id}
          PhotoSelect={() => this.onPhotoSelect(item)}
        />
      );
    });
    let photodetail = null;
    if (this.state.selectedphoto != null) {
      const comments = this.props.comment.abscomments.filter(
        (comment) => comment.AbsphotoId === this.state.selectedphoto.id
      );

      photodetail = (
        <PhotoDetail
          info={this.state.selectedphoto}
          comments={comments}
          absaddComment={this.props.absaddComment}
          commentIsLoading={this.props.comment.isLoading}
          infoClose={()=>this.onClose()}
        />
      );
    }
    
    else{      
      photodetail=(<DefaultPhoto info={this.state.default}/>)
      
    }
    return (
      <div>              
        <Container
          className="themed-container"
          fluid={true}
          style={{ float: "left" }}
        >
          <Row>
            <Col md="7">
              <Row>{gallery}</Row>
            </Col>
            <Col md="4">{photodetail}</Col>
          </Row>
        </Container>
      </div>
    );
  }
}

export default connect(mapStateToProps, mapDispatchToProps)(Mainabstract);
