import React from 'react';
import Loading from '../../Loading';
import dateFormat from 'dateformat';
const LoadComments =props =>{
    console.log(props);
    if(props.commentIsLoading){
        return <Loading/>;
    }
    else{
        return(
            props.comments.map(comment=>{
                return(
                    <div key={comment.id}>
                        <h5 style={{display:"inline"}}>{comment.author}</h5> &nbsp;&nbsp;
                        <p style={{display:"inline"}}>{dateFormat(comment.date,"d-mmm-yy, h:MM, TT")}</p>                        
                        <p>{comment.comment}</p>
                        
                    </div>
                );
            })
    
        );

    }
    
}
export default LoadComments;