import { combineReducers } from "redux";
import * as actionTypes from "./actionTypes";
const photoReducer = (
  photostate = { isLoading: false, photose: [] },
  action
) => {
  switch (action.type) {
    case actionTypes.PHOTOSE_LOADING:
      return {
        ...photostate,
        isLoading: true,
        photose: [],
      };
    case actionTypes.LOAD_PHOTOSE:
      return {
        ...photostate,

        photose: action.payload,
      };
    default:
      return photostate;
  }
};

const commentReducer = (
  commentstate = { isLoading: true, comments: [] },
  action
) => {
  switch (action.type) {
    case actionTypes.LOAD_COMMENTS:
      return {
        ...commentstate,
        isLoading: false,
        comments: action.payload,
      };
    case actionTypes.COMMENT_LOADING:
      return {
        ...commentstate,
        isLoading: true,
        comments: [],
      };
    case actionTypes.ADD_COMMENT:
      let comment = action.payload;
      return {
        ...commentstate,
        comments: commentstate.comments.concat(comment),
      };

    default:
      return commentstate;
  }
};

