import React, { Component } from "react";
import Gallery from "./Gallery";
import PhotoDetail from "./PhotoDetail";
import { Container, Row, Col } from "reactstrap";
import { connect } from "react-redux";
import {baseurl} from "../../baseurl";
import axios from 'axios';
import DefaultPhoto from "./DefaultPhoto";
import {
  nghtaddComment,
  nghtfetchComments,
  nghtfetchPhotose,
} from "../../../redux/actionCreator";

const mapStateToProps = (state) => {
  return {
    photo: state.nght_photose,
    comment: state.nghtcomments,
  };
};
const mapDispatchToProps = (dispatch) => {
  return {
    nghtaddComment: (PhotoId, author, comment) =>
      dispatch(nghtaddComment(PhotoId, author, comment)),
    nghtfetchPhotose: () => dispatch(nghtfetchPhotose()),
    nghtfetchComments: () => dispatch(nghtfetchComments()),
  };
};
class MainNight extends Component {
  state = {
    selectedphoto: null,
    default:[]
  };
  onPhotoSelect = (photo) => {
    this.setState({ selectedphoto: photo });
  };
  onClose=()=>{
    this.setState({selectedphoto:null});
  }
  componentDidMount() {
    this.props.nghtfetchPhotose();
    this.props.nghtfetchComments();
    axios.get(baseurl+"Default")
        .then(res=>res.data[2])
        .then(data=>{this.setState({default:data});});
  }
  
  render() {
    const gallery = this.props.photo.nght_photose.map((item) => {
      return (
        <Gallery
          info={item}
          key={item.id}
          PhotoSelect={() => this.onPhotoSelect(item)}
        />
      );
    });
    let photodetail = null;
    if (this.state.selectedphoto != null) {
      const comments = this.props.comment.nghtcomments.filter(
        (comment) => comment.NghtphotoId === this.state.selectedphoto.id
      );

      photodetail = (
        <PhotoDetail
          info={this.state.selectedphoto}
          comments={comments}
          nghtaddComment={this.props.nghtaddComment}
          commentIsLoading={this.props.comment.isLoading}
          infoClose={()=>this.onClose()}
        />
      );
    }
    else{
      photodetail =(<DefaultPhoto info={this.state.default}/>)
    }
    return (
      <div id="/gallery">        
        <Container
          className="themed-container"
          fluid={true}
          style={{ float: "left" }}
        >
          <Row>
            <Col md="7">
              <Row>{gallery}</Row>
            </Col>
            <Col md="4">{photodetail}</Col>
          </Row>
        </Container>
      </div>
    );
  }
}

export default connect(mapStateToProps, mapDispatchToProps)(MainNight);
