import React from "react";
import { Component } from "react";
import {
  Navbar,
  Nav,
  NavItem,
  NavLink,
  NavbarToggler,
  Collapse,
  
} from "reactstrap";
import { Link, animateScroll as scroll } from "react-scroll";

class Navigation extends Component {
  scrollToTop = () => {
    scroll.scrollToTop();
  };
  constructor(props) {
    super(props);
    this.state = {
      isNavopen: false,
    };
  }
  navToggle = () => {
    this.setState({
      isNavopen: !this.state.isNavopen,
    });
  };
  render() {
    return (
      <div>
        <Navbar
          fixed="top"
          color="dark"
          dark
          expand="sm"
          className="d-flex justify-content-center"
        >      
          <NavbarToggler onClick={this.navToggle} />
          <Collapse isOpen={this.state.isNavopen} navbar>
            <Nav className="nav_center" navbar>             
            <NavItem className="nave_item">
                <NavLink
                  to="/"
                  className="nav-link active"
                  onClick={this.scrollToTop}>
                 Photo
                </NavLink>
              </NavItem>
                <NavItem className="nave_item">
                <Link
                  className="nav-link"
                  to="/gallery"
                  spy={true}
                  smooth={true}
                  offset={-70}
                  duration={500}>
                  Gallery
                </Link> 
                </NavItem>             
            </Nav>
          </Collapse>
        </Navbar>
      </div>
    );
  }
}
export default Navigation;
